fun <A, B, R> zipTransform(
    first: List<A>,
    second: List<B>,
    transform: (A, B) -> R,
): List<R> {
    val minSize = minOf(first.size, second.size)
    return (0 until minSize).map { i -> transform(first[i], second[i]) }
}

