fun <T> slidingWindow(items: List<T>, windowSize: Int): List<List<T>> {
    require(windowSize > 0) { "Window size must be positive" }
    return (0..items.size - windowSize).map { start ->
        items.subList(start, start + windowSize)
    }
}

